  mux_2_4 mux_inst (
    .data({8'b0, in[15:8]}),
    .sel(parity),
    .out(mux_out)
  );
  assign out_hi = parity ? mux_out : out_hi;
  assign out_lo = parity ? out_lo : mux_out;

endmodule

// 4-to-256 demultiplexer
module demux_4_256 (
  input wire [15:0] data,
  input wire [3:0] sel,
  output wire [7:0] out [0:255]
);
  genvar i;
  generate
    for (i = 0; i < 256; i = i + 1) begin : demux_loop
      assign out[i] = data[i*16 +: 8];
    end
  endgenerate
endmodule

// 2-to-4 multiplexer
module mux_2_4 (
  input wire [7:0] data,
  input wire sel,
  output wire [7:0] out
);
