        reg_in <= in;
        reg_hi <= reg_in[15:8];
        reg_lo <= reg_in[7:0];
    end

    assign out_hi = reg_hi;
    assign out_lo = reg_lo;

endmodule

module top_module( 
    input [31:0] a,
    input [15:0] in,
