    splitter splitter_inst(
        .in(in),
        .out_hi(splitter_out_hi),
        .out_lo(splitter_out_lo)
    );

    adder_subtractor adder_subtractor_inst(
        .a(a),
        .b({16{select}} ? splitter_out_lo : splitter_out_hi),
        .sub(sub),
        .out(adder_subtractor_out)
    );

