    input areset,  // async active-high reset to zero
    input load,
    input ena,
    input A, B, SEL, DATA,
    output Y,
    output reg [3:0] Q);

    reg [3:0] shift_reg;
    wire mux_out;

    // 2:1 multiplexer
    assign mux_out = SEL ? DATA : (A & ~B) | (B & ~A);

    // 4-bit shift register
